fn resolve_backend_for_request(req: &Request) -> &'static str {
    let path = req.get_path();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        BACKEND_API
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.starts_with("/css/")
        || path.starts_with("/js/")
    {
        BACKEND_SECONDARY
    } else {
        BACKEND_PRIMARY
    }
}

fn find_backend_config(name: &str) -> Option<BackendConfig> {
    get_backend_configs().into_iter().find(|c| c.name == name)
}

fn create_backend_request(
    original_req: &Request,
    config: &BackendConfig,
) -> Request {
    let mut backend_req = Request::new(original_req.get_method().clone(), original_req.get_url().clone());

    // Copy headers from original request
    for (name, value) in original_req.get_headers() {
        backend_req.set_header(name, value);
    }

    // Set the Host header to match the backend
    backend_req.set_header("Host", config.host);

    // Add forwarding headers
    if let Some(client_ip) = original_req.get_header_str("Fastly-Client-IP") {
        backend_req.set_header("X-Forwarded-For", client_ip);
    }

    backend_req.set_header("X-Forwarded-Proto", "https");
    backend_req.set_header("X-Backend-Name", config.name);

    backend_req
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_header("Content-Type", "application/json")
        .with_body(r#"{"status": "healthy", "service": "edge-router"}"#)
}

fn handle_error(status: StatusCode, message: &str) -> Response {
    let body = format!(
        r#"{{"error": true, "status": {}, "message": "{}"}}"#,
        status.as_u16(),
        message
    );
    Response::from_status(status)
        .with_header("Content-Type", "application/json")
        .with_header("Cache-Control", "no-store, no-cache, must-revalidate")
        .with_body(body)
}

fn add_response_headers(resp: &mut Response, backend_name: &str) {
    resp.set_header("X-Served-By", "fastly-edge-router");
    resp.set_header("X-Backend", backend_name);
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains",
    );
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
}

fn send_to_backend(req: Request, backend_name: &str) -> Result<Response, Error> {
    let backend = Backend::from_name(backend_name)?;
    let resp = req.send(backend)?;
    Ok(resp)
}

fn try_failover(
    original_req: &Request,
    primary_backend: &str,
) -> Result<Response, Error> {
    let failover_backend = match primary_backend {
        BACKEND_PRIMARY => BACKEND_SECONDARY,
        BACKEND_API => BACKEND_PRIMARY,
        _ => BACKEND_PRIMARY,
    };

    eprintln!(
        "Attempting failover from {} to {}",
        primary_backend, failover_backend
    );

    if let Some(config) = find_backend_config(failover_backend) {
        let backend_req = create_backend_request(original_req, &config);
        backend_req.set_header("X-Failover-From", primary_backend);
        send_to_backend(backend_req, failover_backend)
    } else {
        Err(Error::msg("No failover backend available"))
    }
}

fn route_request(mut req: Request) -> Result<Response, Error> {
    // Handle health checks
    if req.get_path() == "/healthz" || req.get_path() == "/health" {
        return Ok(handle_health_check());
    }

    // Block unsupported methods
    match req.get_method() {
        &Method::GET
        | &Method::POST
        | &Method::PUT
        | &Method::DELETE
        | &Method::PATCH
        | &Method::HEAD
        | &Method::OPTIONS => {}
        _ => {
            return Ok(handle_error(
                StatusCode::METHOD_NOT_ALLOWED,
                "Method not allowed",
            ));
        }
    }

    // Determine which backend to route to
    let backend_name = resolve_backend_for_request(&req);

    let config = match find_backend_config(backend_name) {
        Some(c) => c,
        None => {
            return Ok(handle_error(
                StatusCode::BAD_GATEWAY,
                "Backend configuration not found",
            ));
        }
    };

    eprintln!(
        "Routing {} {} to backend {} ({}:{})",
        req.get_method(),
        req.get_path(),
        config.name,
        config.host,
        config.port
    );

    // Create the backend request
    let backend_req = create_backend_request(&req, &config);

    // Send to backend with failover support
    let result = send_to_backend(backend_req, backend_name);

    let mut response = match result {
        Ok(resp) => {
            if resp.get_status().is_server_error() {
                eprintln!(
                    "Backend {} returned error status: {}",
                    backend_name,
                    resp.get_status().as_u16()
                );
                // Attempt failover on 5xx errors
                match try_failover(&req, backend_name) {
                    Ok(failover_resp) => failover_resp,
                    Err(_) => resp, // Return original error response if failover fails
                }
            } else {
                resp
            }
        }
        Err(e) => {
            eprintln!("Backend {} connection error: {}", backend_name, e);
            // Attempt failover
            match try_failover(&req, backend_name) {
                Ok(failover_resp) => failover_resp,
                Err(_) => {
                    return Ok(handle_error(
                        StatusCode::BAD_GATEWAY,
                        &format!("Backend unavailable: {}", backend_name),
                    ));
                }
            }
        }
    };

    // Add standard response headers
    add_response_headers(&mut response, backend_name);

    // Add caching headers for static content
    if backend_name == BACKEND_SECONDARY {
        if !response.get_status().is_server_error() && !response.get_status().is_client_error() {
            response.set_header("Cache-Control", "public, max-age=86400, s-maxage=604800");
            response.set_header("Surrogate-Control", "max-age=604800");
        }
    }

    // Prevent caching of API responses
    if backend_name == BACKEND_API {
        response.set_header("Cache-Control", "no-store, no-cache, must-revalidate, private");
        response.remove_header("Surrogate-Control");
    }

    Ok(response)
}

